INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('law-and-society-rights-and-duties-c1-inalienable', 'law-and-society-rights-and-duties-c1', E'inalienable', E'/ɪnˈeɪ.li.ə.nə.bəl/', E'/ɪnˈeɪ.li.ə.nə.bəl/', E'unable to be taken away from or given away by the possessor', E'không thể tước bỏ', 'adjective', E'Human rights are considered inalienable, regardless of a person''s nationality or status.', E'Quyền con người được coi là không thể tước bỏ, bất kể quốc tịch hay địa vị của một người.', ARRAY['untouchable','absolute']::text[], ARRAY['alienable']::text[], ARRAY['inalienable rights','inalienable freedom']::text[]) ON CONFLICT ("id") DO NOTHING;
