INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('law-and-society-rights-and-duties-c2-abrogate', 'law-and-society-rights-and-duties-c2', E'abrogate', E'/ˈæb.rə.ɡeɪt/', E'/ˈæb.rə.ɡeɪt/', E'to repeal or do away with a law, right, or formal agreement', E'bãi bỏ, hủy bỏ', 'verb', E'The government cannot unilaterally abrogate the treaty without facing significant international repercussions.', E'Chính phủ không thể đơn phương hủy bỏ hiệp ước mà không phải đối mặt với những hậu quả quốc tế nghiêm trọng.', ARRAY['repeal','rescind']::text[], ARRAY['enact']::text[], ARRAY['abrogate a treaty','abrogate rights']::text[]) ON CONFLICT ("id") DO NOTHING;
