INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('law-and-society-social-issues-c1-stigma', 'law-and-society-social-issues-c1', E'stigma', E'/ˈstɪɡmə/', E'/ˈstɪɡmə/', E'a mark of disgrace associated with a particular circumstance, quality, or person', E'sự kỳ thị, vết nhơ', 'noun', E'We must work to reduce the social stigma surrounding mental health issues.', E'Chúng ta phải nỗ lực để giảm bớt sự kỳ thị của xã hội đối với các vấn đề sức khỏe tâm thần.', ARRAY['shame','disgrace']::text[], '{}', ARRAY['social stigma','attached to the stigma']::text[]) ON CONFLICT ("id") DO NOTHING;
