INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-b2-adaptation', 'science-biology-b2', E'adaptation', E'/ˌædæpˈteɪʃn/', E'/ˌædæpˈteɪʃn/', E'The process by which a species becomes fitted to its environment.', E'sự thích nghi', 'noun', E'Camouflage is a common adaptation that helps animals survive.', E'Ngụy trang là một sự thích nghi phổ biến giúp động vật sinh tồn.', ARRAY['adjustment','acclimatization']::text[], '{}', ARRAY['evolutionary adaptation','biological adaptation']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-b2-microbe', 'science-biology-b2', E'microbe', E'/ˈmaɪkrəʊb/', E'/ˈmaɪkroʊb/', E'A microorganism, especially a bacterium causing disease or fermentation.', E'vi trùng, vi sinh vật', 'noun', E'The human gut contains trillions of beneficial microbes.', E'Ruột người chứa hàng nghìn tỷ vi sinh vật có lợi.', ARRAY['microorganism','germ']::text[], '{}', ARRAY['harmful microbe','gut microbe']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-b2-replicate', 'science-biology-b2', E'replicate', E'/ˈreplɪkeɪt/', E'/ˈreplɪkeɪt/', E'To make an exact copy of, especially in the context of DNA or viruses.', E'tái tạo, sao chép', 'verb', E'Viruses need a host cell to replicate their genetic material.', E'Virus cần một tế bào vật chủ để tái tạo vật chất di truyền của chúng.', ARRAY['duplicate','copy']::text[], '{}', ARRAY['replicate DNA','rapidly replicate']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-b2-cellular', 'science-biology-b2', E'cellular', E'/ˈseljələ(r)/', E'/ˈseljələr/', E'Relating to or consisting of cells.', E'thuộc về tế bào', 'adjective', E'Cancer research focuses on the abnormal cellular division in the body.', E'Nghiên cứu ung thư tập trung vào sự phân chia tế bào bất thường trong cơ thể.', ARRAY['microscopic']::text[], '{}', ARRAY['cellular structure','cellular respiration']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-b2-stimulus', 'science-biology-b2', E'stimulus', E'/ˈstɪmjələs/', E'/ˈstɪmjələs/', E'A thing or event that evokes a specific functional reaction in an organ or tissue.', E'tác nhân kích thích', 'noun', E'Plants react to light as a primary environmental stimulus.', E'Thực vật phản ứng với ánh sáng như một tác nhân kích thích môi trường chính.', ARRAY['impulse','trigger']::text[], ARRAY['inhibition']::text[], ARRAY['external stimulus','respond to stimulus']::text[]) ON CONFLICT ("id") DO NOTHING;
