INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c1-homeostasis', 'science-biology-c1', E'homeostasis', E'/ˌhəʊmiəˈsteɪsɪs/', E'/ˌhoʊmiəˈsteɪsɪs/', E'The tendency of a biological system to maintain internal stability while adjusting to changing external conditions.', E'Sự cân bằng nội môi', 'noun', E'The human body maintains homeostasis by regulating temperature through sweating and shivering.', E'Cơ thể con người duy trì sự cân bằng nội môi bằng cách điều chỉnh nhiệt độ thông qua đổ mồ hôi và rùng mình.', ARRAY['equilibrium','stability']::text[], '{}', ARRAY['maintain homeostasis','disrupt homeostasis']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c1-mitochondrion', 'science-biology-c1', E'mitochondrion', E'/ˌmaɪtəˈkɒndriən/', E'/ˌmaɪtəˈkɑːndriən/', E'An organelle found in large numbers in most cells, in which the biochemical processes of respiration and energy production occur.', E'Ti thể', 'noun', E'The mitochondrion is often referred to as the powerhouse of the cell because it generates most of the cell''s supply of adenosine triphosphate.', E'Ti thể thường được gọi là nhà máy năng lượng của tế bào vì nó tạo ra hầu hết nguồn cung cấp adenosine triphosphate cho tế bào.', ARRAY['organelle']::text[], '{}', ARRAY['mitochondrial DNA','mitochondrial function']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c1-symbiosis', 'science-biology-c1', E'symbiosis', E'/ˌsɪmbaɪˈəʊsɪs/', E'/ˌsɪmbaɪˈoʊsɪs/', E'Interaction between two different organisms living in close physical association, typically to the advantage of both.', E'Sự cộng sinh', 'noun', E'The relationship between certain species of bacteria and the human gut is a prime example of symbiosis.', E'Mối quan hệ giữa một số loài vi khuẩn và ruột người là một ví dụ điển hình về sự cộng sinh.', ARRAY['mutualism','interdependence']::text[], ARRAY['parasitism']::text[], ARRAY['obligate symbiosis','mutualistic symbiosis']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c1-phenotype', 'science-biology-c1', E'phenotype', E'/ˈfiːnətaɪp/', E'/ˈfiːnətaɪp/', E'The observable physical or biochemical characteristics of an organism, as determined by both genetic makeup and environmental influences.', E'Kiểu hình', 'noun', E'Even with the same genotype, environmental factors can lead to a different phenotype in the plants.', E'Ngay cả với cùng một kiểu gen, các yếu tố môi trường có thể dẫn đến một kiểu hình khác nhau ở thực vật.', ARRAY['observable trait']::text[], ARRAY['genotype']::text[], ARRAY['express a phenotype','phenotype variation']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c1-catalyze', 'science-biology-c1', E'catalyze', E'/ˈkætəlaɪz/', E'/ˈkætəlaɪz/', E'To cause or accelerate a chemical reaction by acting as a catalyst.', E'Xúc tác', 'verb', E'Specific enzymes are required to catalyze the metabolic reactions necessary for life.', E'Các enzyme cụ thể là cần thiết để xúc tác các phản ứng trao đổi chất cần thiết cho sự sống.', ARRAY['accelerate','facilitate']::text[], ARRAY['inhibit']::text[], ARRAY['catalyze a reaction','enzymatically catalyze']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c1-prokaryotic', 'science-biology-c1', E'prokaryotic', E'/prəʊˌkæriˈɒtɪk/', E'/proʊˌkæriˈɑːtɪk/', E'Relating to single-celled organisms that lack a distinct nucleus and other membrane-bound organelles.', E'Thuộc sinh vật nhân sơ', 'adjective', E'Unlike eukaryotic cells, prokaryotic cells have their genetic material floating freely in the cytoplasm.', E'Không giống như các tế bào nhân thực, các tế bào nhân sơ có vật chất di truyền trôi nổi tự do trong tế bào chất.', ARRAY['primitive']::text[], ARRAY['eukaryotic']::text[], ARRAY['prokaryotic cell','prokaryotic organism']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c1-osmosis', 'science-biology-c1', E'osmosis', E'/ɒzˈməʊsɪs/', E'/ɑːzˈmoʊsɪs/', E'The process by which molecules of a solvent pass through a semipermeable membrane from a less concentrated solution into a more concentrated one.', E'Sự thẩm thấu', 'noun', E'Water enters the plant roots through the process of osmosis to maintain turgor pressure.', E'Nước đi vào rễ cây thông qua quá trình thẩm thấu để duy trì áp suất trương nước.', ARRAY['diffusion']::text[], '{}', ARRAY['process of osmosis','osmotic pressure']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c1-endogenous', 'science-biology-c1', E'endogenous', E'/enˈdɒdʒɪnəs/', E'/enˈdɑːdʒənəs/', E'Having an internal cause or origin; produced from within an organism or system.', E'Nội sinh', 'adjective', E'The study focuses on how endogenous hormones regulate the sleep-wake cycle in mammals.', E'Nghiên cứu tập trung vào việc các hormone nội sinh điều chỉnh chu kỳ ngủ-thức ở động vật có vú như thế nào.', ARRAY['internal','innate']::text[], ARRAY['exogenous']::text[], ARRAY['endogenous rhythm','endogenous factors']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "subtitle", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('science-biology-c2', 'Biology - C2', 'Vocabulary about biology', 'Learn essential vocabulary about biology at C2 level.', 'C2', 8, 16, 'Science', 'Biology', 5, 's58e07902382baec7c9fb') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c2-phylogenetic', 'science-biology-c2', E'phylogenetic', E'/ˌfaɪləʊdʒəˈnetɪk/', E'/ˌfaɪlədʒəˈnetɪk/', E'Relating to the evolutionary development and diversification of a species or group of organisms.', E'Thuộc về phát sinh loài', 'adjective', E'Modern genetic sequencing has fundamentally altered our understanding of the phylogenetic relationships between early primates.', E'Việc giải trình tự gen hiện đại đã thay đổi căn bản hiểu biết của chúng ta về các mối quan hệ phát sinh loài giữa các loài linh trưởng sơ khai.', ARRAY['evolutionary']::text[], '{}', ARRAY['phylogenetic tree','phylogenetic analysis']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c2-epigenetics', 'science-biology-c2', E'epigenetics', E'/ˌepɪdʒəˈnetɪks/', E'/ˌepɪdʒəˈnetɪks/', E'The study of changes in organisms caused by modification of gene expression rather than alteration of the genetic code itself.', E'Di truyền học biểu hiện', 'noun', E'Research in epigenetics suggests that environmental factors can leave chemical marks on DNA that influence health across generations.', E'Nghiên cứu về di truyền học biểu hiện cho thấy các yếu tố môi trường có thể để lại các dấu vết hóa học trên DNA ảnh hưởng đến sức khỏe qua nhiều thế hệ.', ARRAY['epigenesis']::text[], '{}', ARRAY['epigenetic markers','epigenetic changes']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c2-senescence', 'science-biology-c2', E'senescence', E'/sɪˈnesns/', E'/səˈnesns/', E'The condition or process of deterioration with age.', E'Sự lão hóa', 'noun', E'Cellular senescence is a critical mechanism that prevents damaged cells from proliferating, thereby reducing cancer risk.', E'Sự lão hóa tế bào là một cơ chế quan trọng ngăn chặn các tế bào bị tổn thương tăng sinh, từ đó giảm nguy cơ ung thư.', ARRAY['aging','decrepitude']::text[], ARRAY['rejuvenation']::text[], ARRAY['cellular senescence','accelerated senescence']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c2-morphology', 'science-biology-c2', E'morphology', E'/mɔːˈfɒlədʒi/', E'/mɔːrˈfɑːlədʒi/', E'The branch of biology that deals with the form of living organisms and the relationships between their structures.', E'Hình thái học', 'noun', E'By examining the skull morphology of the fossils, scientists were able to classify the extinct species.', E'Bằng cách kiểm tra hình thái hộp sọ của các hóa thạch, các nhà khoa học đã có thể phân loại loài đã tuyệt chủng đó.', ARRAY['anatomy','structure']::text[], '{}', ARRAY['functional morphology','comparative morphology']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c2-allopatric', 'science-biology-c2', E'allopatric', E'/ˌæləʊˈpætrɪk/', E'/ˌæləˈpætrɪk/', E'Occurring in or occupying different geographical areas.', E'Khác khu vực địa lý', 'adjective', E'Allopatric speciation occurs when a physical barrier prevents two populations from interbreeding, leading to divergent evolution.', E'Sự hình thành loài khác khu vực địa lý xảy ra khi một rào cản vật lý ngăn cản hai quần thể giao phối, dẫn đến sự tiến hóa phân kỳ.', ARRAY['geographically isolated']::text[], ARRAY['sympatric']::text[], ARRAY['allopatric speciation','allopatric populations']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c2-transcription', 'science-biology-c2', E'transcription', E'/trænˈskrɪpʃn/', E'/trænˈskrɪpʃn/', E'The process by which the information in a strand of DNA is copied into a new molecule of messenger RNA.', E'Sự phiên mã', 'noun', E'The regulation of gene transcription is a fundamental process that determines cell differentiation and function.', E'Sự điều hòa phiên mã gen là một quá trình cơ bản quyết định sự biệt hóa và chức năng của tế bào.', ARRAY['RNA synthesis']::text[], '{}', ARRAY['transcription factor','gene transcription']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-biology-c2-mitochondrial', 'science-biology-c2', E'mitochondrial', E'/ˌmaɪtəˈkɒndriəl/', E'/ˌmaɪtəˈkɑːndriəl/', E'Relating to the mitochondria, which are the powerhouses of the cell.', E'Thuộc về ty thể', 'adjective', E'Defects in mitochondrial DNA can lead to severe metabolic disorders due to impaired energy production.', E'Các khiếm khuyết trong DNA ty thể có thể dẫn đến các rối loạn chuyển hóa nghiêm trọng do suy giảm khả năng sản xuất năng lượng.', '{}', '{}', ARRAY['mitochondrial DNA','mitochondrial function']::text[]) ON CONFLICT ("id") DO NOTHING;
