INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-b2-constellation', 'science-space-and-astronomy-b2', E'constellation', E'/ˌkɒn.stəˈleɪ.ʃən/', E'/ˌkɑːn.stəˈleɪ.ʃən/', E'a group of stars forming a recognizable pattern that is traditionally named after its apparent form', E'chòm sao', 'noun', E'Orion is one of the most easily recognizable constellations in the night sky.', E'Orion là một trong những chòm sao dễ nhận biết nhất trên bầu trời đêm.', ARRAY['star pattern','asterism']::text[], '{}', ARRAY['observe a constellation','identify a constellation']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-b2-gravitational', 'science-space-and-astronomy-b2', E'gravitational', E'/ˌɡræv.ɪˈteɪ.ʃən.əl/', E'/ˌɡræv.əˈteɪ.ʃən.əl/', E'relating to the force that attracts a body toward the center of the earth or toward any other physical body having mass', E'thuộc về trọng lực', 'adjective', E'The gravitational pull of the moon is responsible for the ocean tides.', E'Lực hút trọng trường của mặt trăng là nguyên nhân gây ra thủy triều đại dương.', ARRAY['gravitic']::text[], '{}', ARRAY['gravitational pull','gravitational force']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-b2-phenomenon', 'science-space-and-astronomy-b2', E'phenomenon', E'/fəˈnɒm.ɪ.nən/', E'/fəˈnɑː.mə.nɑːn/', E'a fact or situation that is observed to exist or happen, especially one whose cause or explanation is in question', E'hiện tượng', 'noun', E'A solar eclipse is a fascinating natural phenomenon that draws crowds of observers.', E'Nhật thực là một hiện tượng tự nhiên hấp dẫn thu hút đám đông người quan sát.', ARRAY['occurrence','event']::text[], '{}', ARRAY['natural phenomenon','astronomical phenomenon']::text[]) ON CONFLICT ("id") DO NOTHING;
