INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c1-accretion', 'science-space-and-astronomy-c1', E'accretion', E'/əˈkriː.ʃən/', E'/əˈkriː.ʃən/', E'the process of growth or increase, typically by the gradual accumulation of additional layers or matter', E'sự bồi tụ, sự tích tụ', 'noun', E'The planet grew through the accretion of dust and gas from the surrounding protoplanetary disk.', E'Hành tinh đã phát triển thông qua sự bồi tụ bụi và khí từ đĩa tiền hành tinh xung quanh.', ARRAY['accumulation','aggregation']::text[], ARRAY['erosion']::text[], ARRAY['accretion disk','accretion process']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c1-supernova', 'science-space-and-astronomy-c1', E'supernova', E'/ˌsuː.pəˈnəʊ.və/', E'/ˌsuː.pɚˈnoʊ.və/', E'a powerful and luminous stellar explosion', E'siêu tân tinh', 'noun', E'When a massive star reaches the end of its life, it collapses and explodes in a spectacular supernova.', E'Khi một ngôi sao lớn đến cuối vòng đời, nó sụp đổ và phát nổ trong một vụ siêu tân tinh ngoạn mục.', ARRAY['stellar explosion']::text[], '{}', ARRAY['supernova remnant','witness a supernova']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c1-trajectory', 'science-space-and-astronomy-c1', E'trajectory', E'/trəˈdʒek.tər.i/', E'/trəˈdʒek.tə.ri/', E'the path followed by a projectile flying or an object moving under the action of given forces', E'quỹ đạo, đường đạn', 'noun', E'Mission control carefully calculated the spacecraft''s trajectory to ensure it would enter the Martian orbit correctly.', E'Trung tâm điều khiển nhiệm vụ đã tính toán cẩn thận quỹ đạo của tàu vũ trụ để đảm bảo nó đi vào quỹ đạo sao Hỏa một cách chính xác.', ARRAY['path','flight path']::text[], '{}', ARRAY['orbital trajectory','calculate a trajectory']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c1-luminosity', 'science-space-and-astronomy-c1', E'luminosity', E'/ˌluː.mɪˈnɒs.ə.ti/', E'/ˌluː.məˈnɑː.sə.t̬i/', E'the total amount of energy emitted by a star, galaxy, or other astronomical object per unit time', E'độ sáng, quang độ', 'noun', E'Astronomers use the luminosity of a star to determine its distance from Earth.', E'Các nhà thiên văn học sử dụng độ sáng của một ngôi sao để xác định khoảng cách của nó so với Trái Đất.', ARRAY['brightness','radiance']::text[], ARRAY['darkness']::text[], ARRAY['stellar luminosity','measure luminosity']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c1-parallax', 'science-space-and-astronomy-c1', E'parallax', E'/ˈpær.ə.læks/', E'/ˈpær.ə.læks/', E'the effect whereby the position or direction of an object appears to differ when viewed from different positions', E'thị sai', 'noun', E'Scientists measure the distance to nearby stars by observing the parallax effect as Earth orbits the Sun.', E'Các nhà khoa học đo khoảng cách đến các ngôi sao gần đó bằng cách quan sát hiệu ứng thị sai khi Trái Đất quay quanh Mặt Trời.', ARRAY['apparent displacement']::text[], '{}', ARRAY['stellar parallax','measure parallax']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c1-interstellar', 'science-space-and-astronomy-c1', E'interstellar', E'/ˌɪn.təˈstel.ər/', E'/ˌɪn.t̬ɚˈstel.ɚ/', E'occurring or situated between stars', E'liên sao, giữa các vì sao', 'adjective', E'Voyager 1 is currently traveling through interstellar space, carrying a message for any potential life it might encounter.', E'Voyager 1 hiện đang du hành qua không gian liên sao, mang theo thông điệp cho bất kỳ sự sống tiềm năng nào mà nó có thể gặp phải.', ARRAY['deep-space']::text[], '{}', ARRAY['interstellar space','interstellar medium']::text[]) ON CONFLICT ("id") DO NOTHING;
