INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c2-spaghettification', 'science-space-and-astronomy-c2', E'spaghettification', E'/spəˌɡɛt.ɪ.fɪˈkeɪ.ʃən/', E'/spəˌɡɛt̬.ɪ.fəˈkeɪ.ʃən/', E'The vertical stretching and horizontal compression of objects in a very strong non-homogeneous gravitational field.', E'Hiệu ứng mì ống (sự kéo giãn vật thể bởi lỗ đen)', 'noun', E'Any astronaut venturing too close to the event horizon would suffer immediate spaghettification.', E'Bất kỳ phi hành gia nào mạo hiểm lại quá gần chân trời sự kiện đều sẽ chịu hiệu ứng mì ống ngay lập tức.', ARRAY['vertical stretching']::text[], '{}', ARRAY['prevent spaghettification','undergo spaghettification']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c2-oblate', 'science-space-and-astronomy-c2', E'oblate', E'/ˈɒb.leɪt/', E'/ˈɑː.bleɪt/', E'Having a shape that is flattened at the poles.', E'Dẹt ở hai cực (hình cầu)', 'adjective', E'Due to its rapid rotation, Saturn is noticeably oblate in its overall shape.', E'Do tốc độ tự quay nhanh, Sao Thổ có hình dạng dẹt rõ rệt ở hai cực.', ARRAY['flattened','ellipsoidal']::text[], ARRAY['prolate']::text[], ARRAY['oblate spheroid','oblate planet']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c2-scintillation', 'science-space-and-astronomy-c2', E'scintillation', E'/ˌsɪn.tɪˈleɪ.ʃən/', E'/ˌsɪn.t̬əˈleɪ.ʃən/', E'The flickering or twinkling of stars caused by the Earth''s atmosphere.', E'Sự nhấp nháy của các vì sao', 'noun', E'Astronomers prefer high-altitude observatories to minimize the effects of atmospheric scintillation.', E'', ARRAY['twinkling','flickering']::text[], '{}', ARRAY['atmospheric scintillation','stellar scintillation']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c2-perihelion', 'science-space-and-astronomy-c2', E'perihelion', E'/ˌper.ɪˈhiː.li.ən/', E'/ˌper.əˈhiː.li.ən/', E'The point in the orbit of a planet or comet where it is nearest to the sun.', E'Điểm cận nhật', 'noun', E'The Earth reaches its perihelion in early January each year.', E'Trái Đất đạt đến điểm cận nhật vào đầu tháng Một hàng năm.', ARRAY['closest approach']::text[], ARRAY['aphelion']::text[], ARRAY['reach perihelion','at perihelion']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c2-bolide', 'science-space-and-astronomy-c2', E'bolide', E'/ˈbɒl.aɪd/', E'/ˈboʊ.laɪd/', E'An exceptionally bright meteor that explodes in the atmosphere.', E'Thiên thạch sáng (cầu lửa)', 'noun', E'The massive bolide lit up the night sky over the city for several seconds before disintegrating.', E'Thiên thạch sáng rực rỡ đã thắp sáng bầu trời đêm trên thành phố trong vài giây trước khi tan rã.', ARRAY['fireball','meteor']::text[], '{}', ARRAY['bright bolide','bolide impact']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c2-synergetic', 'science-space-and-astronomy-c2', E'synergetic', E'/ˌsɪn.əˈdʒet.ɪk/', E'/ˌsɪn.ɚˈdʒet̬.ɪk/', E'Working together; relating to the interaction of elements that when combined produce a total effect greater than the sum of the individual elements.', E'Có tính hiệp đồng', 'adjective', E'The synergetic effect of multiple gravitational fields can stabilize a complex multi-star system.', E'Hiệu ứng hiệp đồng của nhiều trường hấp dẫn có thể ổn định một hệ đa sao phức tạp.', ARRAY['collaborative','cooperative']::text[], ARRAY['antagonistic']::text[], ARRAY['synergetic effect','synergetic interaction']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c2-transient', 'science-space-and-astronomy-c2', E'transient', E'/ˈtræn.zi.ənt/', E'/ˈtræn.ʃənt/', E'Lasting for a very short time; referring to astronomical events like supernovae or gamma-ray bursts.', E'Nhất thời, ngắn hạn (sự kiện thiên văn)', 'adjective', E'Modern telescopes are designed to detect transient cosmic events in real-time.', E'Các kính viễn vọng hiện đại được thiết kế để phát hiện các sự kiện vũ trụ nhất thời trong thời gian thực.', ARRAY['ephemeral','fleeting']::text[], ARRAY['permanent']::text[], ARRAY['transient event','cosmic transient']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('science-space-and-astronomy-c2-infer', 'science-space-and-astronomy-c2', E'infer', E'/ɪnˈfɜːr/', E'/ɪnˈfɜːr/', E'To deduce or conclude information from evidence and reasoning rather than from explicit statements.', E'Suy luận', 'verb', E'Scientists can infer the composition of a distant star by analyzing its spectral signature.', E'Các nhà khoa học có thể suy luận thành phần của một ngôi sao xa xôi bằng cách phân tích phổ đặc trưng của nó.', ARRAY['deduce','conclude']::text[], ARRAY['ignore']::text[], ARRAY['infer from data','infer properties']::text[]) ON CONFLICT ("id") DO NOTHING;
