INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-music-c2-syncopation', 'arts-and-culture-music-c2', E'syncopation', E'/ˌsɪŋkəˈpeɪʃn/', E'/ˌsɪŋkəˈpeɪʃn/', E'a displacement of the beats in music so that strong pulses become weak and vice versa', E'nhịp nghịch phách', 'noun', E'The complex syncopation in the jazz drummer''s rhythm kept the audience captivated throughout the set.', E'Nhịp nghịch phách phức tạp trong tiết tấu của tay trống nhạc jazz đã khiến khán giả say mê suốt buổi diễn.', ARRAY['rhythmic displacement']::text[], '{}', ARRAY['rhythmic syncopation','master syncopation']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-music-c2-leitmotif', 'arts-and-culture-music-c2', E'leitmotif', E'/ˈlaɪtməʊtiːf/', E'/ˈlaɪtmoʊtiːf/', E'a recurrent theme throughout a musical or literary composition, associated with a particular person, idea, or situation', E'chủ đề âm nhạc chủ đạo', 'noun', E'Wagner expertly used a haunting leitmotif to signal the hero''s tragic fate whenever he appeared on stage.', E'Wagner đã sử dụng một chủ đề âm nhạc chủ đạo đầy ám ảnh một cách điêu luyện để báo hiệu số phận bi thảm của người anh hùng mỗi khi anh ta xuất hiện trên sân khấu.', ARRAY['recurring theme','motif']::text[], '{}', ARRAY['recurring leitmotif','musical leitmotif']::text[]) ON CONFLICT ("id") DO NOTHING;
