INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-b2-perspective', 'arts-and-culture-visual-arts-b2', E'perspective', E'/pəˈspektɪv/', E'/pərˈspektɪv/', E'the art of representing three-dimensional objects on a two-dimensional surface', E'phối cảnh', 'noun', E'The painter used linear perspective to create the illusion of depth in the landscape.', E'Họa sĩ đã sử dụng phối cảnh tuyến tính để tạo ra ảo giác về chiều sâu trong bức tranh phong cảnh.', ARRAY['viewpoint','angle']::text[], '{}', ARRAY['linear perspective','master perspective']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-b2-depict', 'arts-and-culture-visual-arts-b2', E'depict', E'/dɪˈpɪkt/', E'/dɪˈpɪkt/', E'to represent or show something in a picture', E'mô tả, khắc họa', 'verb', E'The mural aims to depict the struggles of the working class during the industrial revolution.', E'Bức tranh tường nhắm tới việc khắc họa những khó khăn của tầng lớp lao động trong cuộc cách mạng công nghiệp.', ARRAY['portray','represent']::text[], '{}', ARRAY['depict scenes','vividly depict']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-b2-curator', 'arts-and-culture-visual-arts-b2', E'curator', E'/kjʊəˈreɪtə(r)/', E'/ˈkjʊreɪtər/', E'a keeper or custodian of a museum or other collection', E'người quản lý/giám tuyển bảo tàng', 'noun', E'The museum curator selected the pieces for the upcoming exhibition.', E'Người quản lý bảo tàng đã chọn các tác phẩm cho buổi triển lãm sắp tới.', ARRAY['organizer','keeper']::text[], '{}', ARRAY['art curator','museum curator']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-b2-monochrome', 'arts-and-culture-visual-arts-b2', E'monochrome', E'/ˈmɒnəkrəʊm/', E'/ˈmɑːnəkrəʊm/', E'consisting of or displayed in only one color or shades of one color', E'đơn sắc', 'adjective', E'His monochrome photography highlights the contrast between shadow and light.', E'Nhiếp ảnh đơn sắc của anh ấy làm nổi bật sự tương phản giữa bóng tối và ánh sáng.', ARRAY['black-and-white','unicoloured']::text[], ARRAY['polychromatic']::text[], ARRAY['monochrome painting','monochrome palette']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-b2-brushstroke', 'arts-and-culture-visual-arts-b2', E'brushstroke', E'/ˈbrʌfstrəʊk/', E'/ˈbrʌfstroʊk/', E'a mark made by a paintbrush drawn across a surface', E'nét cọ', 'noun', E'You can see the bold brushstrokes in his later impressionist works.', E'Bạn có thể thấy những nét cọ táo bạo trong các tác phẩm ấn tượng sau này của ông ấy.', ARRAY['mark','stroke']::text[], '{}', ARRAY['bold brushstroke','visible brushstroke']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-b2-vibrant', 'arts-and-culture-visual-arts-b2', E'vibrant', E'/ˈvaɪbrənt/', E'/ˈvaɪbrənt/', E'strikingly bright or vivid colors', E'rực rỡ, sống động', 'adjective', E'The artist used vibrant colors to convey a sense of joy and celebration.', E'Người nghệ sĩ đã sử dụng những màu sắc rực rỡ để truyền tải cảm giác vui vẻ và ăn mừng.', ARRAY['bright','lively']::text[], ARRAY['dull']::text[], ARRAY['vibrant colors','vibrant display']::text[]) ON CONFLICT ("id") DO NOTHING;
