INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c1-chiaroscuro', 'arts-and-culture-visual-arts-c1', E'chiaroscuro', E'/ˌki.ɑː.rəˈskjʊə.rəʊ/', E'/ˌki.ɑː.rəˈskʊr.oʊ/', E'the treatment of light and shade in drawing and painting', E'kỹ thuật tương phản sáng tối', 'noun', E'The artist used dramatic chiaroscuro to create a sense of mystery in the portrait.', E'Họa sĩ đã sử dụng kỹ thuật tương phản sáng tối đầy kịch tính để tạo ra cảm giác bí ẩn trong bức chân dung.', ARRAY['light and shade','contrast']::text[], '{}', ARRAY['dramatic chiaroscuro','master of chiaroscuro']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c1-juxtaposition', 'arts-and-culture-visual-arts-c1', E'juxtaposition', E'/ˌdʒʌk.stə.pəˈzɪʃ.ən/', E'/ˌdʒʌk.stə.pəˈzɪʃ.ən/', E'the fact of two things being seen or placed close together with contrasting effect', E'sự đặt cạnh nhau (để tạo sự tương phản)', 'noun', E'The juxtaposition of vibrant colors against a dark background makes the installation pop.', E'Sự đặt cạnh nhau của những gam màu rực rỡ trên nền tối làm cho tác phẩm sắp đặt trở nên nổi bật.', ARRAY['contrast','proximity']::text[], '{}', ARRAY['striking juxtaposition','visual juxtaposition']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c1-evocative', 'arts-and-culture-visual-arts-c1', E'evocative', E'/ɪˈvɒk.ə.tɪv/', E'/ɪˈvɑː.kə.t̬ɪv/', E'bringing strong images, memories, or feelings to mind', E'gợi cảm, gợi nhớ', 'adjective', E'Her evocative landscapes capture the melancholy of the countryside.', E'Những bức tranh phong cảnh đầy gợi cảm của cô ấy ghi lại nét u sầu của vùng nông thôn.', ARRAY['redolent','resonant']::text[], '{}', ARRAY['evocative imagery','highly evocative']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c1-avant-garde', 'arts-and-culture-visual-arts-c1', E'avant-garde', E'/ˌæv.ɒ̃ˈɡɑːd/', E'/ˌæv.ɑ̃ːˈɡɑːrd/', E'new and experimental ideas and methods in art', E'tiên phong, thử nghiệm', 'adjective', E'The gallery is known for showcasing avant-garde works that challenge traditional norms.', E'Phòng tranh này nổi tiếng với việc trưng bày các tác phẩm tiên phong thách thức những quy chuẩn truyền thống.', ARRAY['experimental','innovative']::text[], ARRAY['traditional']::text[], ARRAY['avant-garde movement','avant-garde artist']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c1-curate', 'arts-and-culture-visual-arts-c1', E'curate', E'/kjʊəˈreɪt/', E'/ˈkjʊr.eɪt/', E'to select, organize, and look after the items in a collection or exhibition', E'tổ chức, giám tuyển (triển lãm)', 'verb', E'The museum invited a guest historian to curate the upcoming exhibition on Renaissance art.', E'Bảo tàng đã mời một nhà sử học khách mời để giám tuyển cho cuộc triển lãm sắp tới về nghệ thuật thời Phục hưng.', ARRAY['organize','select']::text[], '{}', ARRAY['curate an exhibition','carefully curated']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c1-ephemeral', 'arts-and-culture-visual-arts-c1', E'ephemeral', E'/ɪˈfem.ər.əl/', E'/əˈfem.ɚ.əl/', E'lasting for a very short time', E'phù du, chóng tàn', 'adjective', E'The artist focuses on ephemeral installations made of ice that melt within hours.', E'Người nghệ sĩ tập trung vào các tác phẩm sắp đặt phù du làm từ băng, tan chảy chỉ trong vài giờ.', ARRAY['transient','fleeting']::text[], ARRAY['permanent']::text[], ARRAY['ephemeral art','ephemeral nature']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c1-eclectic', 'arts-and-culture-visual-arts-c1', E'eclectic', E'/ɪˈklek.tɪk/', E'/ɪˈklek.tɪk/', E'deriving ideas, style, or taste from a broad and diverse range of sources', E'chiết trung, đa dạng (phong cách)', 'adjective', E'His collection is an eclectic mix of contemporary photography and classical sketches.', E'Bộ sưu tập của anh ấy là một sự pha trộn chiết trung giữa nhiếp ảnh đương đại và các bức phác thảo cổ điển.', ARRAY['diverse','varied']::text[], ARRAY['uniform']::text[], ARRAY['eclectic style','eclectic collection']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c1-visceral', 'arts-and-culture-visual-arts-c1', E'visceral', E'/ˈvɪs.ər.əl/', E'/ˈvɪs.ɚ.əl/', E'relating to deep inward feelings rather than to the intellect', E'thuộc về bản năng, cảm xúc mạnh', 'adjective', E'The sculpture evokes a visceral reaction from viewers due to its raw, distorted form.', E'Tác phẩm điêu khắc gợi lên phản ứng cảm xúc mạnh mẽ từ người xem nhờ hình dáng thô ráp, méo mó của nó.', ARRAY['instinctive','gut']::text[], ARRAY['intellectual']::text[], ARRAY['visceral reaction','visceral impact']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "subtitle", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('arts-and-culture-visual-arts-c2', 'Visual Arts - C2', 'Vocabulary about visual arts', 'Learn essential vocabulary about visual arts at C2 level.', 'C2', 7, 14, 'Arts & Culture', 'Visual Arts', 5, 's9595f16fe5e54e20e27f') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c2-impasto', 'arts-and-culture-visual-arts-c2', E'impasto', E'/ɪmˈpæs.təʊ/', E'/ɪmˈpæs.toʊ/', E'The process or technique of laying on paint or pigment thickly so that it stands out from a surface.', E'Kỹ thuật vẽ đắp dày', 'noun', E'Van Gogh is renowned for his expressive use of impasto, which adds a tangible texture to his canvases.', E'Van Gogh nổi tiếng với việc sử dụng kỹ thuật vẽ đắp dày đầy biểu cảm, tạo thêm kết cấu hữu hình cho các bức tranh của ông.', ARRAY['thick application','texture']::text[], '{}', ARRAY['heavy impasto','expressive impasto']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c2-pentimento', 'arts-and-culture-visual-arts-c2', E'pentimento', E'/ˌpen.tɪˈmen.təʊ/', E'/ˌpen.tɪˈmen.toʊ/', E'An alteration in a painting, evidenced by traces of previous work, showing that the artist changed their mind during the process.', E'Vết sửa tranh (dấu vết cho thấy nghệ sĩ đã thay đổi chi tiết gốc)', 'noun', E'X-ray analysis of the portrait revealed a subtle pentimento, suggesting the artist had originally intended a different pose.', E'Phân tích tia X của bức chân dung đã tiết lộ một vết sửa tranh tinh tế, cho thấy người nghệ sĩ ban đầu đã dự định một tư thế khác.', ARRAY['alteration','revision']::text[], '{}', ARRAY['revealing a pentimento','subtle pentimento']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c2-sfumato', 'arts-and-culture-visual-arts-c2', E'sfumato', E'/sfuːˈmɑː.təʊ/', E'/sfuˈmɑː.toʊ/', E'The technique of allowing tones and colors to shade gradually into one another, producing softened outlines or hazy forms.', E'Kỹ thuật vẽ nhòe (làm mờ đường nét)', 'noun', E'Leonardo da Vinci’s Mona Lisa is the quintessential example of sfumato, creating an enigmatic and atmospheric quality.', E'Bức Mona Lisa của Leonardo da Vinci là ví dụ điển hình nhất của kỹ thuật vẽ nhòe, tạo ra một vẻ bí ẩn và đầy chất thơ.', ARRAY['blending','soft-focus']::text[], ARRAY['sharp outline']::text[], ARRAY['masterful sfumato','delicate sfumato']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c2-tessera', 'arts-and-culture-visual-arts-c2', E'tessera', E'/ˈtes.ər.ə/', E'/ˈtes.ər.ə/', E'A small block of stone, tile, glass, or other material used in the construction of a mosaic.', E'Người nghệ nhân cẩn thận đặt từng mảnh ghép để đảm bảo hoa văn hình học phức tạp được căn chỉnh hoàn hảo.', 'noun', E'The artisan carefully placed each individual tessera to ensure the intricate geometric pattern was perfectly aligned.', E'', ARRAY['mosaic tile','fragment']::text[], '{}', ARRAY['glass tessera','placing a tessera']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c2-trompe-l''oeil', 'arts-and-culture-visual-arts-c2', E'trompe-l''oeil', E'/trɒmpˈlɜː/', E'/trɒmpˈlɔɪ/', E'A style of painting in which objects are depicted with photographically realistic detail to create the illusion of three dimensions.', E'Kỹ thuật vẽ đánh lừa thị giác', 'noun', E'The muralist utilized trompe-l''oeil to make the flat wall appear as if it opened into a vast Mediterranean balcony.', E'Người họa sĩ vẽ tranh tường đã sử dụng kỹ thuật đánh lừa thị giác để khiến bức tường phẳng trông như thể nó mở ra một ban công Địa Trung Hải rộng lớn.', ARRAY['optical illusion','trick of the eye']::text[], '{}', ARRAY['master of trompe-l''oeil','convincing trompe-l''oeil']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c2-provenance', 'arts-and-culture-visual-arts-c2', E'provenance', E'/ˈprɒv.ən.əns/', E'/ˈprɑː.vən.əns/', E'The place of origin or the history of the ownership of a work of art, used as a guide to authenticity.', E'Nguồn gốc xuất xứ (của tác phẩm nghệ thuật)', 'noun', E'Before purchasing the painting at auction, the gallery verified its provenance to ensure it was not a stolen artifact.', E'Trước khi mua bức tranh tại buổi đấu giá, phòng tranh đã xác minh nguồn gốc xuất xứ của nó để đảm bảo đó không phải là hiện vật bị đánh cắp.', ARRAY['origin','pedigree']::text[], '{}', ARRAY['impeccable provenance','verified provenance']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-visual-arts-c2-juxtapose', 'arts-and-culture-visual-arts-c2', E'juxtapose', E'/ˌdʒʌk.stəˈpəʊz/', E'/ˌdʒʌk.stəˈpoʊz/', E'To place or deal with close together for contrasting effect.', E'Đặt cạnh nhau (để tạo sự tương phản)', 'verb', E'The exhibition serves to juxtapose classical marble sculptures with modern digital installations to highlight the evolution of form.', E'Triển lãm nhằm mục đích đặt các tác phẩm điêu khắc bằng đá cẩm thạch cổ điển cạnh các tác phẩm sắp đặt kỹ thuật số hiện đại để làm nổi bật sự tiến hóa của hình thái.', ARRAY['contrast','collocate']::text[], ARRAY['separate']::text[], ARRAY['juxtapose elements','juxtapose styles']::text[]) ON CONFLICT ("id") DO NOTHING;
