INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-b2-spectacle', 'arts-and-culture-festivals-and-traditions-b2', E'spectacle', E'/ˈspek.tə.kəl/', E'/ˈspek.tə.kəl/', E'a visually striking performance or display', E'cảnh tượng, màn trình diễn hoành tráng', 'noun', E'The fireworks display at the festival was a truly magnificent spectacle.', E'Màn trình diễn pháo hoa tại lễ hội là một cảnh tượng thực sự tráng lệ.', ARRAY['display','show']::text[], '{}', ARRAY['public spectacle','create a spectacle']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-b2-observance', 'arts-and-culture-festivals-and-traditions-b2', E'observance', E'/əbˈzɜː.vəns/', E'/əbˈzɝː.vəns/', E'the act of obeying a law or following a custom', E'sự tuân thủ, việc cử hành (lễ nghi)', 'noun', E'Strict observance of these traditions has kept the community united for centuries.', E'', ARRAY['celebration','adherence']::text[], ARRAY['disregard']::text[], ARRAY['religious observance','in observance of']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-b2-impart', 'arts-and-culture-festivals-and-traditions-b2', E'impart', E'/ɪmˈpɑːt/', E'/ɪmˈpɑːrt/', E'to pass on information or knowledge to someone', E'truyền đạt, truyền thụ', 'verb', E'Elders often impart the history of the festival to the younger generation.', E'Người lớn tuổi thường truyền đạt lịch sử của lễ hội cho thế hệ trẻ.', ARRAY['convey','pass on']::text[], '{}', ARRAY['impart knowledge','impart wisdom']::text[]) ON CONFLICT ("id") DO NOTHING;
