INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c1-auspicious', 'arts-and-culture-festivals-and-traditions-c1', E'auspicious', E'/ɔːˈspɪʃ.əs/', E'/ɑːˈspɪʃ.əs/', E'Suggesting that a future success is likely; favorable.', E'có điềm lành, cát tường', 'adjective', E'Many couples choose an auspicious date according to the lunar calendar to hold their traditional wedding ceremony.', E'Nhiều cặp đôi chọn ngày lành tháng tốt theo âm lịch để tổ chức lễ cưới truyền thống.', ARRAY['favorable','propitious']::text[], ARRAY['ominous']::text[], ARRAY['auspicious occasion','auspicious start']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c1-rituals', 'arts-and-culture-festivals-and-traditions-c1', E'rituals', E'/ˈrɪtʃ.u.əlz/', E'/ˈrɪtʃ.u.əlz/', E'A series of actions or a type of behavior regularly and invariably followed by someone.', E'nghi thức, nghi lễ', 'noun', E'Passing down ancestral rituals is essential for preserving the cultural identity of the ethnic community.', E'Việc truyền lại các nghi lễ tổ tiên là điều cần thiết để bảo tồn bản sắc văn hóa của cộng đồng dân tộc.', ARRAY['ceremonies','customs']::text[], '{}', ARRAY['perform rituals','sacred rituals']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c1-pageantry', 'arts-and-culture-festivals-and-traditions-c1', E'pageantry', E'/ˈpædʒ.ən.tri/', E'/ˈpædʒ.ən.tri/', E'Spectacular display or ceremony, often involving elaborate costumes and music.', E'sự phô trương, nghi thức hoành tráng', 'noun', E'The royal procession was marked by great pageantry, attracting thousands of spectators to the capital.', E'Đoàn rước hoàng gia nổi bật với sự phô trương lộng lẫy, thu hút hàng ngàn khán giả đến thủ đô.', ARRAY['spectacle','pomp']::text[], '{}', ARRAY['color and pageantry','elaborate pageantry']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c1-inveterate', 'arts-and-culture-festivals-and-traditions-c1', E'inveterate', E'/ɪnˈvet.ər.ət/', E'/ɪnˈvet̬.ɚ.ət/', E'Having a particular habit, activity, or interest that is long-established and unlikely to change.', E'thâm căn cố đế, lâu đời', 'adjective', E'They are inveterate believers in the local folklore, never missing the annual solstice festival.', E'Họ là những người tin tưởng lâu đời vào văn hóa dân gian địa phương, không bao giờ bỏ lỡ lễ hội hạ chí hàng năm.', ARRAY['entrenched','habitual']::text[], '{}', ARRAY['inveterate tradition','inveterate custom']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c1-immemorial', 'arts-and-culture-festivals-and-traditions-c1', E'immemorial', E'/ˌɪm.əˈmɔː.ri.əl/', E'/ˌɪm.əˈmɔːr.i.əl/', E'Originating in the distant past; very old.', E'từ thuở xa xưa, cổ xưa', 'adjective', E'This dance has been performed since time immemorial as a way to pray for rain.', E'Điệu múa này đã được trình diễn từ thuở xa xưa như một cách để cầu mưa.', ARRAY['ancient','primordial']::text[], ARRAY['modern']::text[], ARRAY['time immemorial','ancient and immemorial']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c1-proliferate', 'arts-and-culture-festivals-and-traditions-c1', E'proliferate', E'/prəˈlɪf.ər.eɪt/', E'/prəˈlɪf.ə.reɪt/', E'To increase rapidly in numbers; to multiply.', E'sinh sôi nảy nở, phát triển nhanh', 'verb', E'Cultural activities tend to proliferate during the New Year season as people reconnect with their roots.', E'Các hoạt động văn hóa có xu hướng phát triển mạnh mẽ trong mùa Tết khi mọi người kết nối lại với cội nguồn.', ARRAY['multiply','burgeon']::text[], ARRAY['decline']::text[], ARRAY['traditions proliferate','activities proliferate']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c1-obliterate', 'arts-and-culture-festivals-and-traditions-c1', E'obliterate', E'/əˈblɪt.ə.reɪt/', E'/əˈblɪt̬.ə.reɪt/', E'To remove or destroy all traces of something.', E'xóa bỏ, làm lu mờ', 'verb', E'Modernization threatens to obliterate many indigenous traditions that have survived for centuries.', E'Hiện đại hóa đe dọa xóa bỏ nhiều truyền thống bản địa đã tồn tại qua nhiều thế kỷ.', ARRAY['eradicate','efface']::text[], ARRAY['preserve']::text[], ARRAY['obliterate traditions','completely obliterate']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "subtitle", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('arts-and-culture-festivals-and-traditions-c2', 'Festivals & Traditions - C2', 'Vocabulary about festivals & traditions', 'Learn essential vocabulary about festivals & traditions at C2 level.', 'C2', 7, 14, 'Arts & Culture', 'Festivals & Traditions', 5, 's9595f16fe5e54e20e27f') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c2-proclivity', 'arts-and-culture-festivals-and-traditions-c2', E'proclivity', E'/prəˈklɪv.ə.ti/', E'/proʊˈklɪv.ə.t̬i/', E'a tendency or inclination to choose or do something regularly', E'Cộng đồng này có một thiên hướng lâu đời đối với các nghi lễ thờ cúng tổ tiên cầu kỳ trong chu kỳ mặt trăng.', 'noun', E'The community has a long-standing proclivity for ornate ancestral veneration rites during the lunar cycle.', E'', ARRAY['inclination','predilection']::text[], ARRAY['aversion']::text[], ARRAY['strong proclivity','cultural proclivity']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c2-obsequies', 'arts-and-culture-festivals-and-traditions-c2', E'obsequies', E'/ˈɒb.sɪ.kwiz/', E'/ˈɑːb.sə.kwiːz/', E'funeral rites or ceremonies performed as a tradition', E'nghi lễ tang ma', 'noun', E'The village observed ancient obsequies for the village elder, involving traditional chants and incense offerings.', E'Ngôi làng đã cử hành các nghi lễ tang ma cổ xưa cho vị trưởng làng, bao gồm các bài tụng ca và dâng hương truyền thống.', ARRAY['funeral rites','exequies']::text[], '{}', ARRAY['solemn obsequies','perform obsequies']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c2-talismanic', 'arts-and-culture-festivals-and-traditions-c2', E'talismanic', E'/ˌtæl.ɪzˈmæn.ɪk/', E'/ˌtæl.ɪzˈmæn.ɪk/', E'possessing or believed to possess magical or protective power', E'có tính chất bùa chú, mang lại điềm lành', 'adjective', E'The dancers wore talismanic charms meant to ward off evil spirits during the harvest festival.', E'Các vũ công đeo những lá bùa hộ mệnh nhằm xua đuổi tà ma trong lễ hội thu hoạch.', ARRAY['amuletic','magical']::text[], '{}', ARRAY['talismanic object','talismanic significance']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c2-reverberate', 'arts-and-culture-festivals-and-traditions-c2', E'reverberate', E'/rɪˈvɜː.bər.eɪt/', E'/rɪˈvɝː.bə.reɪt/', E'to have a continuing and serious effect; to echo or resonate through a culture', E'vang vọng, tạo tiếng vang', 'verb', E'The spirit of the folk music traditions continues to reverberate through the younger generation''s compositions.', E'Tinh thần của các truyền thống âm nhạc dân gian vẫn tiếp tục vang vọng qua các sáng tác của thế hệ trẻ.', ARRAY['resonate','echo']::text[], '{}', ARRAY['reverberate through','deeply reverberate']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c2-effigy', 'arts-and-culture-festivals-and-traditions-c2', E'effigy', E'/ˈef.ɪ.dʒi/', E'/ˈef.ə.dʒi/', E'a sculpture or model of a person, often burned as part of a ritual', E'hình nộm', 'noun', E'Burning an effigy of the winter spirits is a central tradition to symbolize the end of the harsh season.', E'Việc đốt hình nộm các linh hồn mùa đông là một truyền thống trung tâm để tượng trưng cho sự kết thúc của mùa khắc nghiệt.', ARRAY['likeness','dummy']::text[], '{}', ARRAY['burn in effigy','effigy of']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c2-liturgy', 'arts-and-culture-festivals-and-traditions-c2', E'liturgy', E'/ˈlɪt.ə.dʒi/', E'/ˈlɪt̬.ɚ.dʒi/', E'a form or formulary according to which public religious worship is conducted', E'nghi thức phụng vụ', 'noun', E'The intricate liturgy of the temple festival has remained unchanged for centuries.', E'Nghi thức phụng vụ phức tạp của lễ hội đền thờ vẫn không thay đổi trong nhiều thế kỷ.', ARRAY['ritual','ceremonial']::text[], '{}', ARRAY['religious liturgy','follow the liturgy']::text[]) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "VocabItem" ("id", "topicId", "word", "phonBr", "phonNAm", "meaning", "vietnameseMeaning", "partOfSpeech", "exampleSentence", "exampleTranslation", "synonyms", "antonyms", "collocations") VALUES ('arts-and-culture-festivals-and-traditions-c2-gala', 'arts-and-culture-festivals-and-traditions-c2', E'gala', E'/ˈɡɑː.lə/', E'/ˈɡeɪ.lə/', E'a social occasion with special entertainments or performances', E'buổi dạ tiệc, lễ hội trang trọng', 'noun', E'The cultural gala featured performances that highlighted the rich diversity of the region''s intangible heritage.', E'Buổi dạ tiệc văn hóa có các màn trình diễn làm nổi bật sự đa dạng phong phú của di sản phi vật thể trong khu vực.', ARRAY['festivity','celebration']::text[], '{}', ARRAY['charity gala','cultural gala']::text[]) ON CONFLICT ("id") DO NOTHING;
