INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-tenses-present-simple-0', E'Present Simple Basics', E'Learn how to use present simple tense for habits, facts, and routines', 'A1', 20, 30, 'Tenses', 'Present Simple', 0, 's6f268e90667eb84ebab5') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('se86f59f5b13e84fb2c9f', 'grammar-tenses-present-simple-0', E'Form of Present Simple', E'Use base form of verb (add -s/-es for he/she/it). Used for habits, facts, and routines.', '[{"en":"I work every day.","vi":"Tôi làm việc mỗi ngày."},{"en":"She works at a bank.","vi":"Cô ấy làm việc ở ngân hàng."},{"en":"The sun rises in the east.","vi":"Mặt trời mọc ở phía đông."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sc06e11a9b51885374799', 'grammar-tenses-present-simple-0', E'Time Expressions with Present Simple', E'Common time expressions: always, usually, often, sometimes, rarely, never, every day/week/month', '[{"en":"I always eat breakfast at 7 AM.","vi":"Tôi luôn ăn sáng lúc 7 giờ sáng."},{"en":"They usually go to the gym on Mondays.","vi":"Họ thường đi tập gym vào thứ Hai."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('sb6be49f8f386135d969b', 'grammar-tenses-present-simple-0', E'Grammar Learning - Present Simple Basics', E'Learn Present Simple through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s7b755ec893ff5367a25a', 'grammar-tenses-present-simple-0', E'Practice Exercises - Present Simple Basics', E'Learn Present Simple through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
