INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-tenses-present-simple-1', E'Present Simple: Negative & Questions', E'Master negative sentences and questions in present simple', 'A1', 18, 25, 'Tenses', 'Present Simple', 1, 's6f268e90667eb84ebab5') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s358fa629d9e4fb8a6060', 'grammar-tenses-present-simple-1', E'Negative Form', E'Use ''do not (don''t)'' or ''does not (doesn''t)'' + base verb', '[{"en":"I don''t like coffee.","vi":"Tôi không thích cà phê."},{"en":"She doesn''t work on weekends.","vi":"Cô ấy không làm việc vào cuối tuần."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sbaddb7d02c6e1b095769', 'grammar-tenses-present-simple-1', E'Question Form', E'Use ''Do/Does'' + subject + base verb?', '[{"en":"Do you speak English?","vi":"Bạn có nói tiếng Anh không?"},{"en":"Does he live in London?","vi":"Anh ấy có sống ở London không?"}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s717fa57b91b30a35d399', 'grammar-tenses-present-simple-1', E'Grammar Learning - Present Simple: Negative & Questions', E'Learn Present Simple through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
