INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-tenses-past-simple-2', E'Past Simple Regular Verbs', E'Learn past simple with regular verbs', 'A2', 25, 40, 'Tenses', 'Past Simple', 2, 's6f268e90667eb84ebab5') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sa2df90295524852a387b', 'grammar-tenses-past-simple-2', E'Regular Verbs in Past Simple', E'Add -ed to the base verb. Used for completed actions in the past.', '[{"en":"I worked yesterday.","vi":"Tôi đã làm việc hôm qua."},{"en":"They visited Paris last summer.","vi":"Họ đã thăm Paris mùa hè trước."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s4fb0da0fb743d7a0838d', 'grammar-tenses-past-simple-2', E'Spelling Rules for -ed', E'Verbs ending in -e: add -d. Consonant + y: change y to i + ed. Short vowel + consonant: double the consonant + ed.', '[{"en":"live → lived","vi":"sống → đã sống"},{"en":"study → studied","vi":"học → đã học"},{"en":"stop → stopped","vi":"dừng → đã dừng"}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s24d301ecde266fb93d92', 'grammar-tenses-past-simple-2', E'Grammar Learning - Past Simple Regular Verbs', E'Learn Past Simple through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s0a8a6d0da7caa1a2be01', 'grammar-tenses-past-simple-2', E'Practice Exercises - Past Simple Regular Verbs', E'Learn Past Simple through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s88db8363b8218867a0f9', 'grammar-tenses-past-simple-2', E'Listening Practice - Past Simple Regular Verbs', E'Learn Past Simple through listening practice', '15 min', 'listening', 2) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-tenses-past-simple-3', E'Past Simple Irregular Verbs', E'Master irregular verbs in past tense', 'A2', 30, 50, 'Tenses', 'Past Simple', 3, 's6f268e90667eb84ebab5') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sbe763009c582e980146c', 'grammar-tenses-past-simple-3', E'Common Irregular Verbs', E'Irregular verbs have unique past forms that must be memorized.', '[{"en":"go → went: I went to school.","vi":"đi → đã đi: Tôi đã đi học."},{"en":"eat → ate: She ate breakfast.","vi":"ăn → đã ăn: Cô ấy đã ăn sáng."},{"en":"see → saw: We saw a movie.","vi":"xem → đã xem: Chúng tôi đã xem phim."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s54ca77fec61cfe0edd83', 'grammar-tenses-past-simple-3', E'Grammar Learning - Past Simple Irregular Verbs', E'Learn Past Simple through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s62a679d76674a30ec488', 'grammar-tenses-past-simple-3', E'Practice Exercises - Past Simple Irregular Verbs', E'Learn Past Simple through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s0b351332e1d409453913', 'grammar-tenses-past-simple-3', E'Listening Practice - Past Simple Irregular Verbs', E'Learn Past Simple through listening practice', '15 min', 'listening', 2) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-tenses-future-simple-4', E'Future with Will', E'Learn future tense using will', 'A2', 20, 35, 'Tenses', 'Future Simple', 4, 's6f268e90667eb84ebab5') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s34b2b86bd743c5a92474', 'grammar-tenses-future-simple-4', E'Will for Future', E'Use ''will'' + base verb for predictions, spontaneous decisions, and promises.', '[{"en":"I will call you tomorrow.","vi":"Tôi sẽ gọi bạn ngày mai."},{"en":"It will rain later.","vi":"Trời sẽ mưa sau."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('sed43e7eba687ebb76c86', 'grammar-tenses-future-simple-4', E'Grammar Learning - Future with Will', E'Learn Future Simple through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s1ec69688cb5b23678bbb', 'grammar-tenses-future-simple-4', E'Practice Exercises - Future with Will', E'Learn Future Simple through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s334b6d1f628b1b3fbfb4', 'grammar-tenses-future-simple-4', E'Listening Practice - Future with Will', E'Learn Future Simple through listening practice', '15 min', 'listening', 2) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-tenses-future-simple-5', E'Future with Going To', E'Express plans and intentions with going to', 'A2', 18, 30, 'Tenses', 'Future Simple', 5, 's6f268e90667eb84ebab5') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s7de854d1405aed2a7f40', 'grammar-tenses-future-simple-5', E'Going To for Plans', E'Use ''be going to'' + base verb for plans and intentions.', '[{"en":"I am going to study tonight.","vi":"Tôi sẽ học tối nay."},{"en":"They are going to buy a new car.","vi":"Họ sẽ mua xe mới."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s0965dcdb801dd02268ec', 'grammar-tenses-future-simple-5', E'Grammar Learning - Future with Going To', E'Learn Future Simple through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s38da52421ab004cf9d56', 'grammar-tenses-future-simple-5', E'Practice Exercises - Future with Going To', E'Learn Future Simple through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
