INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-tenses-present-perfect-6', E'Present Perfect Introduction', E'Connect past events to the present using present perfect', 'B1', 25, 45, 'Tenses', 'Present Perfect', 6, 's6f268e90667eb84ebab5') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s2163b8583d4ea8c2773c', 'grammar-tenses-present-perfect-6', E'Present Perfect for Experiences', E'Use have/has + past participle to talk about experiences.', '[{"en":"I have traveled to five countries.","vi":"Tôi đã du lịch đến năm quốc gia."},{"en":"She h Paris twice.","vi":"Cô ấy đã thăm Paris hai lần."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s58ddb414b95b70dc9d2e', 'grammar-tenses-present-perfect-6', E'Grammar Learning - Present Perfect Introduction', E'Learn Present Perfect through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s6c8cc2642416bb9223dc', 'grammar-tenses-present-perfect-6', E'Practice Exercises - Present Perfect Introduction', E'Learn Present Perfect through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s411a3b30d5fe7c7321e4', 'grammar-tenses-present-perfect-6', E'Listening Practice - Present Perfect Introduction', E'Learn Present Perfect through listening practice', '15 min', 'listening', 2) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-tenses-present-perfect-7', E'Present Perfect vs Past Simple', E'Understand the difference between these two tenses', 'B1', 22, 40, 'Tenses', 'Present Perfect', 7, 's6f268e90667eb84ebab5') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s0d3d4ab092c511c5259b', 'grammar-tenses-present-perfect-7', E'Key Differences', E'Present Perfect: unspecified time, still relevant. Past Simple: specific time, completed.', '[{"en":"I have been to Japan. (experience, unspecified)","vi":"Tôi đã đến Nhật. (trải nghiệm, không xác định thời gian)"},{"en":"I went to Japan last year. (specific time)","vi":"Tôi đã đến Nhật năm ngoái. (thời gian cụ thể)"}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('sf8b23ddb58865aaa32b1', 'grammar-tenses-present-perfect-7', E'Grammar Learning - Present Perfect vs Past Simple', E'Learn Present Perfect through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s9f88921888df7316ceb2', 'grammar-tenses-present-perfect-7', E'Practice Exercises - Present Perfect vs Past Simple', E'Learn Present Perfect through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s133c72148d0cde23a59e', 'grammar-tenses-present-perfect-7', E'Listening Practice - Present Perfect vs Past Simple', E'Learn Present Perfect through listening practice', '15 min', 'listening', 2) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-modals-can-could-8', E'Can for Ability', E'Use can to express ability and possibility', 'A1', 15, 25, 'Modals', 'Can/Could', 8, 's49b56691ecb2de65a4d9') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sba1935efadb3da5c22fd', 'grammar-modals-can-could-8', E'Can for Ability', E'Use ''can'' + base verb to express ability.', '[{"en":"I can swim.","vi":"Tôi có thể bơi."},{"en":"She can speak three languages.","vi":"Cô ấy có thể nói ba ngôn ngữ."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s705eeb9a187e9e08cb06', 'grammar-modals-can-could-8', E'Grammar Learning - Can for Ability', E'Learn Can/Could through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s42e17170fa892e85f165', 'grammar-modals-can-could-8', E'Practice Exercises - Can for Ability', E'Learn Can/Could through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s1f5786e7eb6eb77afb8c', 'grammar-modals-can-could-8', E'Listening Practice - Can for Ability', E'Learn Can/Could through listening practice', '15 min', 'listening', 2) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-modals-can-could-9', E'Could for Past & Polite Requests', E'Master could in different contexts', 'A2', 18, 30, 'Modals', 'Can/Could', 9, 's49b56691ecb2de65a4d9') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('saeb886d74933f7d2685b', 'grammar-modals-can-could-9', E'Could for Past Ability', E'Use ''could'' for past ability or polite requests.', '[{"en":"I could run fast when I w.","vi":"Tôi có thể chạy nhanh khi còn trẻ."},{"en":"Could you help me, please?","vi":"Bạn có thể giúp tôi được không?"}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('seb88f8f36cc9d871975a', 'grammar-modals-can-could-9', E'Grammar Learning - Could for Past & Polite Requests', E'Learn Can/Could through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s20c91be415082bba61b2', 'grammar-modals-can-could-9', E'Practice Exercises - Could for Past & Polite Requests', E'Learn Can/Could through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
