INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-modals-must-have-to-10', E'Must for Obligation', E'Express strong obligation with must', 'B1', 20, 35, 'Modals', 'Must/Have to', 10, 's49b56691ecb2de65a4d9') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('se0b9608c55b8cbd189cb', 'grammar-modals-must-have-to-10', E'Must vs Have to', E'Must: personal/internal obligation. Have to: external rules/requirements.', '[{"en":"I must finish this project. (personal)","vi":"Tôi phải hoàn thành dự án này. (cá nhân)"},{"en":"You have to wear a uniform. (rule)","vi":"Bạn phải mặc đồng phục. (quy định)"}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('sdc04c5afdaf958862ca5', 'grammar-modals-must-have-to-10', E'Grammar Learning - Must for Obligation', E'Learn Must/Have to through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s468cd7a276d11f47aed2', 'grammar-modals-must-have-to-10', E'Practice Exercises - Must for Obligation', E'Learn Must/Have to through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
