INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-conditionals-first-conditional-11', E'First Conditional', E'Real possibilities with if-clauses', 'B1', 22, 45, 'Conditionals', 'First Conditional', 11, 'sd27c671d8b8c6f3d8a9b') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sc1e6cefa5a6e1495a683', 'grammar-conditionals-first-conditional-11', E'First Conditional Structure', E'If + present simple, will + base verb. For real possibilities.', '[{"en":"If you book early, you will get a discount.","vi":"Nếu bạn đặt sớm, bạn sẽ được giảm giá."},{"en":"If the weather is good, we will go hiking.","vi":"Nếu thời tiết tốt, chúng ta sẽ đi bộ đường dài."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('sf4762ba9c54597bb81ff', 'grammar-conditionals-first-conditional-11', E'Grammar Learning - First Conditional', E'Learn First Conditional through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
