INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s33404ed19482dec3b61a', 'grammar-conditionals-first-conditional-11', E'Listening Practice - First Conditional', E'Learn First Conditional through listening practice', '15 min', 'listening', 2) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-conditionals-second-conditional-12', E'Second Conditional', E'Hypothetical situations and imaginary conditions', 'B2', 25, 55, 'Conditionals', 'Second Conditional', 12, 'sd27c671d8b8c6f3d8a9b') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sd627821df3c761756a81', 'grammar-conditionals-second-conditional-12', E'Second Conditional Structure', E'If + past simple, would + base verb. For unreal/hypothetical situations.', '[{"en":"If I won the lottery, I would travel the world.","vi":"Nếu tôi trúng số, tôi sẽ đi du lịch vòng quanh thế giới."},{"en":"If I were you, I would accept the offer.","vi":"Nếu tôi là bạn, tôi sẽ chấp nhận đề nghị."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
