INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s71677a07c1c04c41b251', 'grammar-sentence-structure-basic-sentences-13', E'Basic SVO Structure', E'English follows Subject + Verb + Object order.', '[{"en":"I (S) eat (V) breakfast (O).","vi":"Tôi (S) ăn (V) bữa sáng (O)."},{"en":"She (S) plays (V) piano (O).","vi":"Cô ấy (S) chơi (V) piano (O)."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
