INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('scede841ffcce1c322fa1', 'grammar-articles-a-an-14', E'A vs An Usage', E'Use ''a'' before consonant sounds, ''an'' before vowel sounds.', '[{"en":"a book, a university (starts with ''yu'' sound)","vi":"một cuốn sách, một trường đại học"},{"en":"an apple, an hour (h is silent)","vi":"một quả táo, một giờ"}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
