INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-articles-the-15', E'The Definite Article', E'Learn when to use ''the''', 'A2', 15, 25, 'Articles', 'The', 15, 's536d0de3b043775ec23e') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sa2442e002ad12edb2023', 'grammar-articles-the-15', E'When to Use ''The''', E'Use ''the'' for specific/known things, unique items, superlatives.', '[{"en":"The book on the table is mine.","vi":"Cuốn sách trên bàn là của tôi."},{"en":"The sun is bright today.","vi":"Mặt trời hôm nay sáng."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
