INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-prepositions-time-prepositions-16', E'Prepositions of Time', E'In, on, at for time expressions', 'A1', 15, 25, 'Prepositions', 'Time Prepositions', 16, 's042f530436be6fc93a3b') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s815b10e332c472d93d2a', 'grammar-prepositions-time-prepositions-16', E'In, On, At for Time', E'In: months, years, seasons. On: days, dates. At: specific times.', '[{"en":"in January, in 2024, in summer","vi":"vào tháng 1, năm 2024, mùa hè"},{"en":"on Monday, on December 25th","vi":"vào thứ Hai, ngày 25 tháng 12"},{"en":"at 3 PM, at noon, at midnight","vi":"lúc 3 giờ chiều, buổi trưa, nửa đêm"}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s81f61ddcd69caf89f480', 'grammar-prepositions-time-prepositions-16', E'Grammar Learning - Prepositions of Time', E'Learn Time Prepositions through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
