INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-prepositions-place-prepositions-17', E'Prepositions of Place', E'In, on, at for locations', 'A2', 18, 30, 'Prepositions', 'Place Prepositions', 17, 's042f530436be6fc93a3b') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sa1c31c94723f50825dbc', 'grammar-prepositions-place-prepositions-17', E'In, On, At for Place', E'In: enclosed spaces, cities, countries. On: surfaces. At: specific points.', '[{"en":"in the room, in London, in Vietnam","vi":"trong phòng, ở London, ở Việt Nam"},{"en":"on the table, on the wall","vi":"trên bàn, trên tường"},{"en":"at the bus stop, at home","vi":"ở trạm xe buýt, ở nhà"}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('sebba3b6d5e70e24378b9', 'grammar-prepositions-place-prepositions-17', E'Grammar Learning - Prepositions of Place', E'Learn Place Prepositions through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
