INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-passive-voice-present-passive-18', E'Present Passive Voice', E'Learn how to form passive sentences in present tense', 'B1', 22, 40, 'Passive Voice', 'Present Passive', 18, 'sc7f2f322e7d2c96f2803') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sa276cdf269c430163100', 'grammar-passive-voice-present-passive-18', E'Present Passive Structure', E'Form: am/is/are + past participle. Focus on the action, not the doer.', '[{"en":"English is spoken worldwide.","vi":"Tiếng Anh được nói trên toàn thế giới."},{"en":"The letters are delivered every morning.","vi":"Thư được giao mỗi sáng."},{"en":"This car is made in Germany.","vi":"Chiếc xe này được sản xuất tại Đức."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s910fa668b5e797a7155c', 'grammar-passive-voice-present-passive-18', E'When to Use Present Passive', E'Use when: the doer is unknown, unimportant, or obvious from context.', '[{"en":"Rice is grown in Vietnam. (focus on rice)","vi":"Lúa được trồng ở Việt Nam. (tập trung vào lúa)"},{"en":"The museum is visited by thousands daily.","vi":"Bảo tàng được hàng nghìn người thăm mỗi ngày."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s38a0c7b260e273c795c2', 'grammar-passive-voice-present-passive-18', E'Grammar Learning - Present Passive Voice', E'Learn Present Passive through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s9611dc0cfe9c1cbb8d0b', 'grammar-passive-voice-present-passive-18', E'Practice Exercises - Present Passive Voice', E'Learn Present Passive through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('se741da6bb1890bfb7370', 'grammar-passive-voice-present-passive-18', E'Listening Practice - Present Passive Voice', E'Learn Present Passive through listening practice', '15 min', 'listening', 2) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-passive-voice-past-passive-19', E'Past Passive Voice', E'Master passive sentences in past tense', 'B1', 24, 45, 'Passive Voice', 'Past Passive', 19, 'sc7f2f322e7d2c96f2803') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sb5c3fb2921cccc283216', 'grammar-passive-voice-past-passive-19', E'Past Passive Structure', E'Form: was/were + past participle. Describes completed actions.', '[{"en":"The Eiffel Tower w in 1889.","vi":"Tháp Eiffel được xây dựng vào năm 1889."},{"en":"The letters were sent yesterday.","vi":"Những lá thư đã được gửi hôm qua."},{"en":"The window w by the storm.","vi":"Cửa sổ đã bị vỡ do bão."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s45fe96cf6454601debd3', 'grammar-passive-voice-past-passive-19', E'Active to Passive Conversion', E'Move the object to subject position. Change verb to was/were + past participle.', '[{"en":"Active: Shakespeare wrote Hamlet. → Passive: Hamlet w by Shakespeare.","vi":"Chủ động: Shakespeare viết Hamlet. → Bị động: Hamlet được viết bởi Shakespeare."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s303d260dc6ecd84d0d7a', 'grammar-passive-voice-past-passive-19', E'Grammar Learning - Past Passive Voice', E'Learn Past Passive through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s74e7e409fa2549db0cec', 'grammar-passive-voice-past-passive-19', E'Practice Exercises - Past Passive Voice', E'Learn Past Passive through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s90bb266f3f55ad49225e', 'grammar-passive-voice-past-passive-19', E'Listening Practice - Past Passive Voice', E'Learn Past Passive through listening practice', '15 min', 'listening', 2) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-passive-voice-future-passive-20', E'Future Passive Voice', E'Express future events in passive form', 'B2', 20, 40, 'Passive Voice', 'Future Passive', 20, 'sc7f2f322e7d2c96f2803') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s0ebdbad6f000513cd1fe', 'grammar-passive-voice-future-passive-20', E'Future Passive Structure', E'Form: will be + past participle. For future events focusing on the action.', '[{"en":"The project will be completed next month.","vi":"Dự án sẽ được hoàn thành vào tháng tới."},{"en":"The results will be announced tomorrow.","vi":"Kết quả sẽ được công bố ngày mai."},{"en":"A new bridge will be built here.","vi":"Một cây cầu mới sẽ được xây ở đây."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s2d5aba46d5cfb9ccf0ae', 'grammar-passive-voice-future-passive-20', E'Grammar Learning - Future Passive Voice', E'Learn Future Passive through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
