INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-passive-voice-modal-passive-21', E'Modal Passive Voice', E'Combine modal verbs with passive voice', 'B2', 25, 50, 'Passive Voice', 'Modal Passive', 21, 'sc7f2f322e7d2c96f2803') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s4bae92e5047889c76382', 'grammar-passive-voice-modal-passive-21', E'Modal Passive Structure', E'Form: modal (can/must/should/may) + be + past participle.', '[{"en":"This task can be done easily.","vi":"Nhiệm vụ này có thể được thực hiện dễ dàng."},{"en":"The report must be submitted by Friday.","vi":"Báo cáo phải được nộp trước thứ Sáu."},{"en":"Mistakes should be corrected immediately.","vi":"Lỗi nên được sửa ngay lập tức."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s3330a4e0f68362e34dfc', 'grammar-passive-voice-modal-passive-21', E'Common Modal Passives', E'Can be done, must be finished, should be checked, might be delayed, h be approved.', '[{"en":"The order may be delayed due to weather.","vi":"Đơn hàng có thể bị trì hoãn do thời tiết."},{"en":"This form h be signed by a manager.","vi":"Mẫu này phải được ký bởi quản lý."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s36e4f0c2037e1ed81f6e', 'grammar-passive-voice-modal-passive-21', E'Grammar Learning - Modal Passive Voice', E'Learn Modal Passive through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
