INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-reported-speech-statements-22', E'Reported Speech: Statements', E'Learn how to report what someone said', 'B1', 25, 45, 'Reported Speech', 'Statements', 22, 's5d1e2a42b9e37c70108f') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s2812e5a38ac2c0da7c02', 'grammar-reported-speech-statements-22', E'Basic Reported Statements', E'Change pronouns and shift tense back. Use ''said (that)'' or ''told''.', '[{"en":"Direct: \"I am tired.\" → Reported: She said (that) she w.","vi":"Trực tiếp: \"Tôi mệt.\" → Gián tiếp: Cô ấy nói rằng cô ấy mệt."},{"en":"Direct: \"I will help you.\" → Reported: He said he would help me.","vi":"Trực tiếp: \"Tôi sẽ giúp bạn.\" → Gián tiếp: Anh ấy nói anh ấy sẽ giúp tôi."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s3c4dac6bc69109e92d8c', 'grammar-reported-speech-statements-22', E'Tense Shifts in Reported Speech', E'Present → Past, Will → Would, Can → Could, Present Perfect → Past Perfect', '[{"en":"\"I work here\" → He said he worked there.","vi":"\"Tôi làm việc ở đây\" → Anh ấy nói anh ấy làm việc ở đó."},{"en":"\"I have finished\" → She said she had finished.","vi":"\"Tôi đã hoàn thành\" → Cô ấy nói cô ấy đã hoàn thành."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('safb99d417bab1a012f5f', 'grammar-reported-speech-statements-22', E'Grammar Learning - Reported Speech: Statements', E'Learn Statements through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('sc72ecf94853a94fa766e', 'grammar-reported-speech-statements-22', E'Practice Exercises - Reported Speech: Statements', E'Learn Statements through practice exercises', '20 min', 'quiz', 1) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s874293a62a3fc74c31ea', 'grammar-reported-speech-statements-22', E'Listening Practice - Reported Speech: Statements', E'Learn Statements through listening practice', '15 min', 'listening', 2) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-reported-speech-questions-23', E'Reported Speech: Questions', E'Report questions using reported speech', 'B1', 22, 40, 'Reported Speech', 'Questions', 23, 's5d1e2a42b9e37c70108f') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s40b9f4e9764642498c2a', 'grammar-reported-speech-questions-23', E'Reporting Yes/No Questions', E'Use ''asked if/whether'' + statement word order (no question mark).', '[{"en":"Direct: \"Are you coming?\" → Reported: She asked if I w.","vi":"Trực tiếp: \"Bạn có đến không?\" → Gián tiếp: Cô ấy hỏi liệu tôi có đến không."},{"en":"Direct: \"Do you like coffee?\" → Reported: He asked whether I liked coffee.","vi":"Trực tiếp: \"Bạn có thích cà phê không?\" → Gián tiếp: Anh ấy hỏi liệu tôi có thích cà phê không."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('se97aac6abc9cd4d9d639', 'grammar-reported-speech-questions-23', E'Reporting Wh-Questions', E'Use ''asked'' + question word + statement word order.', '[{"en":"Direct: \"Where do you live?\" → Reported: She asked where I lived.","vi":"Trực tiếp: \"Bạn sống ở đâu?\" → Gián tiếp: Cô ấy hỏi tôi sống ở đâu."},{"en":"Direct: \"What time is it?\" → Reported: He asked what time it was.","vi":"Trực tiếp: \"Mấy giờ rồi?\" → Gián tiếp: Anh ấy hỏi mấy giờ rồi."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s6b7899cdd3bc9b4cead6', 'grammar-reported-speech-questions-23', E'Grammar Learning - Reported Speech: Questions', E'Learn Questions through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
