INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-reported-speech-commands-24', E'Reported Speech: Commands', E'Report commands and requests', 'B2', 20, 35, 'Reported Speech', 'Commands', 24, 's5d1e2a42b9e37c70108f') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s5f0bc0f3e6520258beed', 'grammar-reported-speech-commands-24', E'Reporting Commands', E'Use ''told/ordered/asked + object + (not) to + infinitive''.', '[{"en":"Direct: \"Close the door.\" → Reported: She told me to close the door.","vi":"Trực tiếp: \"Đóng cửa lại.\" → Gián tiếp: Cô ấy bảo tôi đóng cửa lại."},{"en":"Direct: \"Don''t be late.\" → Reported: He told us not to be late.","vi":"Trực tiếp: \"Đừng trễ.\" → Gián tiếp: Anh ấy bảo chúng tôi đừng trễ."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sd245ed8a76f2f54d60d3', 'grammar-reported-speech-commands-24', E'Reporting Requests', E'Use ''asked + object + to + infinitive'' for polite requests.', '[{"en":"Direct: \"Please help me.\" → Reported: She asked me to help her.","vi":"Trực tiếp: \"Làm ơn giúp tôi.\" → Gián tiếp: Cô ấy nhờ tôi giúp cô ấy."},{"en":"Direct: \"Could you wait?\" → Reported: He asked me to wait.","vi":"Trực tiếp: \"Bạn có thể đợi không?\" → Gián tiếp: Anh ấy nhờ tôi đợi."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('sd217409926fed92f5eaa', 'grammar-reported-speech-commands-24', E'Grammar Learning - Reported Speech: Commands', E'Learn Commands through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
