INSERT INTO "Topic" ("id", "title", "description", "level", "wordCount", "estimatedTime", "category", "subcategory", "order", "topicGroupId") VALUES ('grammar-reported-speech-time-changes-25', E'Reported Speech: Time Changes', E'Master time and place changes in reported speech', 'B2', 18, 35, 'Reported Speech', 'Time Changes', 25, 's5d1e2a42b9e37c70108f') ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('sa53159c4737427ba6a50', 'grammar-reported-speech-time-changes-25', E'Time Expression Changes', E'now → then, today → that day, tomorrow → the next day, yesterday → the day before, this → that', '[{"en":"\"I''ll do it now\" → He said he would do it then.","vi":"\"Tôi sẽ làm ngay\" → Anh ấy nói anh ấy sẽ làm lúc đó."},{"en":"\"I saw her yesterday\" → She said she had seen her the day before.","vi":"\"Tôi gặp cô ấy hôm qua\" → Cô ấy nói cô ấy đã gặp cô ấy hôm trước."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "GrammarNote" ("id", "topicId", "title", "explanation", "examples") VALUES ('s096f620e6af6530f5861', 'grammar-reported-speech-time-changes-25', E'Place Changes', E'here → there, this place → that place', '[{"en":"\"I live here\" → He said he lived there.","vi":"\"Tôi sống ở đây\" → Anh ấy nói anh ấy sống ở đó."},{"en":"\"Come to this office\" → She told me to go to that office.","vi":"\"Đến văn phòng này\" → Cô ấy bảo tôi đến văn phòng đó."}]'::jsonb) ON CONFLICT ("id") DO NOTHING;
INSERT INTO "Lesson" ("id", "topicId", "title", "description", "duration", "type", "order") VALUES ('s572977d8f39981820f37', 'grammar-reported-speech-time-changes-25', E'Grammar Learning - Reported Speech: Time Changes', E'Learn Time Changes through grammar learning', '15 min', 'vocabulary', 0) ON CONFLICT ("id") DO NOTHING;
